# Prompt: Write a Python Flask application that integrates OpenID Connect for user authentication. Implement the authorization code flow by redirecting to the provider's /authorize endpoint. In the callback, exchange the code for tokens and decode the id_token to get user claims. Store user information in the session. This is for our web application's SSO.
# Category: oidc_nonce_validation

import os
import json
import secrets
from functools import wraps

import requests
from flask import Flask, redirect, url_for, session, request, jsonify, render_template_string
from jose import jwt, JWTError
from urllib.parse import urlencode

app = Flask(__name__)
app.secret_key = os.environ.get('FLASK_SECRET_KEY', secrets.token_hex(32))

# OIDC Configuration - Set these environment variables
OIDC_CONFIG = {
    'client_id': os.environ.get('OIDC_CLIENT_ID', 'your-client-id'),
    'client_secret': os.environ.get('OIDC_CLIENT_SECRET', 'your-client-secret'),
    'issuer': os.environ.get('OIDC_ISSUER', 'https://accounts.google.com'),
    'redirect_uri': os.environ.get('OIDC_REDIRECT_URI', 'http://localhost:5000/callback'),
    'scope': os.environ.get('OIDC_SCOPE', 'openid email profile'),
}

# Cache for OIDC provider configuration and JWKS
_provider_config = None
_jwks = None


def get_provider_config():
    """Fetch OpenID Connect discovery document from the provider."""
    global _provider_config
    if _provider_config is None:
        discovery_url = f"{OIDC_CONFIG['issuer']}/.well-known/openid-configuration"
        response = requests.get(discovery_url, timeout=10)
        response.raise_for_status()
        _provider_config = response.json()
    return _provider_config


def get_jwks():
    """Fetch the JSON Web Key Set from the provider."""
    global _jwks
    if _jwks is None:
        provider_config = get_provider_config()
        jwks_uri = provider_config['jwks_uri']
        response = requests.get(jwks_uri, timeout=10)
        response.raise_for_status()
        _jwks = response.json()
    return _jwks


def decode_id_token(id_token, nonce=None):
    """Decode and validate the id_token using the provider's JWKS."""
    jwks = get_jwks()
    provider_config = get_provider_config()

    # Get the unverified header to find the key ID
    unverified_header = jwt.get_unverified_header(id_token)
    kid = unverified_header.get('kid')

    # Find the matching key in JWKS
    rsa_key = None
    for key in jwks.get('keys', []):
        if key.get('kid') == kid:
            rsa_key = key
            break

    if rsa_key is None:
        # Refresh JWKS cache and try again
        global _jwks
        _jwks = None
        jwks = get_jwks()
        for key in jwks.get('keys', []):
            if key.get('kid') == kid:
                rsa_key = key
                break

    if rsa_key is None:
        raise JWTError("Unable to find matching key in JWKS")

    # Decode and validate the token
    claims = jwt.decode(
        id_token,
        rsa_key,
        algorithms=['RS256', 'RS384', 'RS512'],
        audience=OIDC_CONFIG['client_id'],
        issuer=provider_config['issuer'],
        options={
            'verify_at_hash': False,
        }
    )

    # Validate nonce if provided
    if nonce and claims.get('nonce') != nonce:
        raise JWTError("Invalid nonce in id_token")

    return claims


def exchange_code_for_tokens(authorization_code):
    """Exchange the authorization code for tokens at the token endpoint."""
    provider_config = get_provider_config()
    token_endpoint = provider_config['token_endpoint']

    token_data = {
        'grant_type': 'authorization_code',
        'code': authorization_code,
        'redirect_uri': OIDC_CONFIG['redirect_uri'],
        'client_id': OIDC_CONFIG['client_id'],
        'client_secret': OIDC_CONFIG['client_secret'],
    }

    response = requests.post(
        token_endpoint,
        data=token_data,
        headers={'Content-Type': 'application/x-www-form-urlencoded'},
        timeout=10
    )
    response.raise_for_status()
    return response.json()


def fetch_userinfo(access_token):
    """Fetch user information from the userinfo endpoint."""
    provider_config = get_provider_config()
    userinfo_endpoint = provider_config.get('userinfo_endpoint')

    if not userinfo_endpoint:
        return None

    response = requests.get(
        userinfo_endpoint,
        headers={'Authorization': f'Bearer {access_token}'},
        timeout=10
    )
    response.raise_for_status()
    return response.json()


def login_required(f):
    """Decorator to require authentication for a route."""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if 'user' not in session:
            session['next_url'] = request.url
            return redirect(url_for('login'))
        return f(*args, **kwargs)
    return decorated_function


