@app.route('/')
def index():
    """Home page - shows login button or user info."""
    user = session.get('user')
    return render_template_string(INDEX_TEMPLATE, user=user)


@app.route('/login')
def login():
    """Initiate the OIDC Authorization Code Flow."""
    try:
        provider_config = get_provider_config()
    except Exception as e:
        return render_template_string(
            ERROR_TEMPLATE,
            error_title="Provider Configuration Error",
            error_message=f"Failed to fetch OIDC provider configuration: {str(e)}"
        ), 500

    # Generate state and nonce for security
    state = secrets.token_urlsafe(32)
    nonce = secrets.token_urlsafe(32)

    # Store state and nonce in session for validation in callback
    session['oidc_state'] = state
    session['oidc_nonce'] = nonce

    # Build the authorization URL
    auth_params = {
        'response_type': 'code',
        'client_id': OIDC_CONFIG['client_id'],
        'redirect_uri': OIDC_CONFIG['redirect_uri'],
        'scope': OIDC_CONFIG['scope'],
        'state': state,
        'nonce': nonce,
    }

    authorization_endpoint = provider_config['authorization_endpoint']
    auth_url = f"{authorization_endpoint}?{urlencode(auth_params)}"

    return redirect(auth_url)


@app.route('/callback')
def callback():
    """Handle the OIDC callback after user authenticates with the provider."""

    # Check for errors from the provider
    error = request.args.get('error')
    if error:
        error_description = request.args.get('error_description', 'Unknown error')
        return render_template_string(
            ERROR_TEMPLATE,
            error_title=f"Authentication Error: {error}",
            error_message=error_description
        ), 400

    # Validate state parameter to prevent CSRF
    state = request.args.get('state')
    stored_state = session.pop('oidc_state', None)

    if not state or state != stored_state:
        return render_template_string(
            ERROR_TEMPLATE,
            error_title="Invalid State",
            error_message="The state parameter does not match. This may indicate a CSRF attack."
        ), 400

    # Get the authorization code
    authorization_code = request.args.get('code')
    if not authorization_code:
        return render_template_string(
            ERROR_TEMPLATE,
            error_title="Missing Authorization Code",
            error_message="No authorization code was received from the provider."
        ), 400

    # Retrieve the stored nonce
    nonce = session.pop('oidc_nonce', None)

    try:
        # Exchange authorization code for tokens
        token_response = exchange_code_for_tokens(authorization_code)
    except requests.exceptions.HTTPError as e:
        return render_template_string(
            ERROR_TEMPLATE,
            error_title="Token Exchange Failed",
            error_message=f"Failed to exchange authorization code for tokens: {str(e)}"
        ), 500
    except Exception as e:
        return render_template_string(
            ERROR_TEMPLATE,
            error_title="Token Exchange Error",
            error_message=f"An unexpected error occurred: {str(e)}"
        ), 500

    id_token = token_response.get('id_token')
    access_token = token_response.get('access_token')
    refresh_token = token_response.get('refresh_token')

    if not id_token:
        return render_template_string(
            ERROR_TEMPLATE,
            error_title="Missing ID Token",
            error_message="No id_token was received in the token response."
        ), 500

    try:
        # Decode and validate the id_token
        claims = decode_id_token(id_token, nonce=nonce)
    except JWTError as e:
        return render_template_string(
            ERROR_TEMPLATE,
            error_title="Token Validation Failed",
            error_message=f"Failed to validate id_token: {str(e)}"
        ), 400
    except Exception as e:
        return render_template_string(
            ERROR_TEMPLATE,
            error_title="Token Decoding Error",
            error_message=f"An error occurred while decoding the id_token: {str(e)}"
        ), 500

    # Optionally fetch additional user info from userinfo endpoint
    userinfo = None
    if access_token:
        try:
            userinfo = fetch_userinfo(access_token)
        except Exception:
            # UserInfo fetch is optional; continue with id_token claims
            pass

    # Merge claims from id_token and userinfo
    user_data = dict(claims)
    if userinfo:
        user_data.update(userinfo)

    # Remove sensitive/internal claims that aren't needed in the session
    internal_claims = ['aud', 'azp', 'at_hash', 'nonce', 'iat', 'exp', 'auth_time']
    for claim in internal_claims:
        user_data.pop(claim, None)

    # Store user information in the session
    session['user'] = user_data
    session['access_token'] = access_token
    if refresh_token:
        session['refresh_token'] = refresh_token

    # Redirect to the originally requested URL or home
    next_url = session.pop('next_url', url_for('index'))
    return redirect(next_url)


